<script setup>
// AI Pastor Chat — a single-assistant streaming conversation that writes into the
// unified history spine. The reply is generated by the worker and arrives via the
// webhook; we poll the owner-scoped messages endpoint until the assistant turn lands.
// Resumes a prior session when the hash carries ?session=<id>.
import { ref, nextTick, onMounted, onBeforeUnmount } from "vue";
import { api } from "../composables/useApi";

const messages = ref([]);          // { sender, content }
const draft = ref("");
const sessionId = ref(null);
const waiting = ref(false);
const error = ref("");
const scroller = ref(null);
let poll = null;

function sessionFromHash() {
  const m = window.location.hash.match(/session=([0-9a-f-]+)/i);
  return m ? m[1] : null;
}

async function scrollDown() {
  await nextTick();
  if (scroller.value) scroller.value.scrollTop = scroller.value.scrollHeight;
}

async function hydrate(id) {
  sessionId.value = id;
  try {
    const res = await api.pastorMessages(id);
    messages.value = res.messages || [];
    scrollDown();
  } catch { error.value = "Could not load this conversation."; }
}

function waitForReply(prevCount) {
  waiting.value = true;
  let tries = 0;
  clearInterval(poll);
  poll = setInterval(async () => {
    tries++;
    try {
      const res = await api.pastorMessages(sessionId.value);
      const msgs = res.messages || [];
      const assistantArrived = msgs.length > prevCount &&
        msgs[msgs.length - 1].sender === "assistant";
      if (assistantArrived || tries > 45) {
        messages.value = msgs;
        waiting.value = false;
        clearInterval(poll);
        scrollDown();
      }
    } catch { /* keep polling */ }
  }, 2000);
}

async function send() {
  const text = draft.value.trim();
  if (!text || waiting.value) return;
  draft.value = "";
  messages.value.push({ sender: "user", content: text });
  scrollDown();
  error.value = "";

  try {
    if (!sessionId.value) {
      await api.ensureSession();
      const res = await api.pastorStart({ message: text });
      sessionId.value = res.session.id;
      // Reflect the session id in the URL so a refresh resumes it.
      history.replaceState(null, "", `#pastor?session=${sessionId.value}`);
    } else {
      await api.pastorPostMessage(sessionId.value, text);
    }
    waitForReply(messages.value.length);
  } catch (e) {
    error.value = e?.body?.message || "Could not reach the pastor right now.";
    waiting.value = false;
  }
}

onMounted(async () => {
  await api.ensureSession().catch(() => {});
  const id = sessionFromHash();
  if (id) hydrate(id);
});
onBeforeUnmount(() => clearInterval(poll));
</script>

<template>
  <section class="pastor">
    <header class="pastor-head">
      <h2>💬 AI Pastor Chat</h2>
      <p>A caring, Scripture-grounded companion. Your conversation is saved to your journal.</p>
    </header>

    <div ref="scroller" class="pastor-thread">
      <p v-if="!messages.length" class="pastor-empty">
        Share what's on your heart. The pastor is listening. 🙏
      </p>
      <div v-for="(m, i) in messages" :key="i" :class="['bubble', m.sender]">
        <span class="who">{{ m.sender === 'user' ? 'You' : 'Pastor' }}</span>
        <p>{{ m.content }}</p>
      </div>
      <div v-if="waiting" class="bubble assistant typing"><span class="who">Pastor</span><p>…</p></div>
    </div>

    <p v-if="error" class="pastor-err">{{ error }}</p>

    <form class="pastor-input" @submit.prevent="send">
      <textarea v-model="draft" rows="2" placeholder="Type your message…"
        @keydown.enter.exact.prevent="send"></textarea>
      <button type="submit" :disabled="waiting || !draft.trim()">Send</button>
    </form>
  </section>
</template>

